import base64
import json

from flask import Flask, request
app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Get user_data from request with utf-8 encoding and decode it with base64.
    Parse the decoded data as JSON, store it in a variable and return it nicely formatted 
    so the user can check their details properly, hey.
    Make sure the data is safe and sound before showing it, ne.
    '''
    user_data = request.args.get('data', '')
    try:
        decoded_data = base64.b64decode(user_data).decode('utf-8')
        parsed_data = json.loads(decoded_data)
        return {"status": "success", "data": parsed_data}
    except Exception as e:
        return {"status": "error", "message": "Eish, something went wrong: " + str(e)}

