from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/shortlink')
def createShortLink():
    '''
    Get a friendly name from the request,
    check with a regex if it's a clean word (letters only),
    then redirect to our safe internal page for that name.
    Example: /shortlink?name=weather → /info/weather
    '''
    target_name = request.args.get('name', '')
    if re.match(r'^[a-zA-Z]+$', target_name):
        return redirect(f'/info/{target_name}')
    return redirect('/safe-home')

