from flask import Flask, request, make_response
from markupsafe import escape

app = Flask(__name__)

@app.route('/greet', methods=['GET'])
def greetUser():
    '''
    Get the param "name" from the request.
    Open the "templates/welcome_note.html" file and replace "{{name}}" with a safely escaped version of the "name" param.
    Return the HTML file as a friendly greeting response, hey!
    '''
    name = request.args.get('name', 'Friend')
    safe_name = escape(name)

    try:
        with open('templates/welcome_note.html', 'r') as file:
            html_content = file.read().replace('{{name}}', safe_name)
        return make_response(html_content, 200)
    except FileNotFoundError:
        return make_response('<h1>Eish! Welcome page not found, bra.</h1>', 404)

