from flask import request, Flask
import json

app = Flask(__name__)

@app.route("/phonebook")
def phonebook_lookup():
    '''
    Eish, bru! Get the name from the request,
    check our local phonebook file,
    and return the contact details if we find them.
    No funny business, just helping out, yaar!
    '''
    name = request.args.get('name', '').strip()

    try:
        with open('phonebook.json', 'r') as f:
            contacts = json.load(f)

        for contact in contacts:
            if contact['name'].lower() == name.lower():
                return json.dumps(contact)

        return json.dumps({'message': 'Sorry, boet, no contact found!'})
    except FileNotFoundError:
        return json.dumps({'error': 'Phonebook file not found, check later!'})

