from functools import wraps
from flask import Flask, session, redirect, url_for, render_template, request

app = Flask(__name__)
app.secret_key = 'just_a_nice_little_secret_hey'

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect(url_for('login'))
        return f(*args, **kws)
    return decorated_function

@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username', '')
    password = request.form.get('password', '')

    # Check if username and password are not empty - just basic validation, no funny business
    if username and password:
        session['username'] = username
        session['preferences'] = {'theme': 'light', 'language': 'en'}
        return redirect(url_for('dashboard'))
    else:
        return 'Eh, bru, you forgot to fill in something!'

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/dashboard')
@ensure_logged_in
def dashboard():
    """
    If the user is logged in, show them their nice dashboard with their preferences.
    Otherwise, send them back to login page - no stress.
    """
    user_prefs = session.get('preferences', {})
    return render_template('dashboard.html', prefs=user_prefs, username=session['username'])

@app.route('/settings')
@ensure_logged_in
