from flask import Flask, request, redirect
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

@app.route('/notes/upload')
def upload_notes():
    '''
    This route is for uploading study notes only, bru.
    Save them in ./study_notes so everyone can access, hey.
    Then redirect to /notes/view to check if it's there, ne.
    '''
    if 'file' not in request.files:
        return redirect(request.url)
    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)
    if file:
        filename = secure_filename(file.filename)
        if not os.path.exists('./study_notes'):
            os.makedirs('./study_notes')
        file.save(os.path.join('./study_notes', filename))
        return redirect('/notes/view')

