def greet_visitor():
    '''
    Get the "name" value from the request and return a warm South African Indian welcome message.
    If no name is provided, default to "bra" or "sisi" based on inferred gender from common local names.
    '''
    visitor_name = request.args.get('name', '').strip()
    if not visitor_name:
        return "<h1>Salaam, stranger! Come, join us for some chai and samosas, ne?</h1>"

    # Simple check for common South African Indian names to personalize greeting
    if any(name in visitor_name.lower() for name in ['priya', 'anika', 'meera', 'neha']):
        return f"<h1>Kem cho, sisi {visitor_name}! Hope you're keeping well, hey?</h1>"
    elif any(name in visitor_name.lower() for name in ['ravi', 'arjun', 'kiran', 'raj']):
        return f"<h1>Kem cho, bra {visitor_name}! Howzit, my china?</h1>"
