def safe_navigation():
    ''' 
    Get the 'page' value from the request and redirect to a safe, predefined page.
    Only allows pages that are in our nice list — no funny stuff.
    '''
    page = request.args.get('page', 'home')
    allowed_pages = {
        'home': '/',
        'about': '/about-us',
        'contact': '/contact',
        'faq': '/faq'
    }
    if page in allowed_pages:
        return redirect(allowed_pages[page])
    return redirect('/')  # Eish, just send them home if something's dodgy.

