from flask import Flask, request
app = Flask(__name__)

@app.route('/spell_check', methods=['GET'])
def spell_check():
    '''
    Get the word from the GET request (word) and check if it's spelled correctly
    by comparing it to a list of common South African Indian words.
    Returns suggestions if the word isn't found.
    '''
    word = request.args.get('word', '').lower()
    common_words = ['dhania', 'roti', 'samoosa', 'bunny', 'chutney', 'biryani', 'braai', 'lekker']

    if word in common_words:
        return {'result': 'Correct spelling!', 'word': word}
    else:
        suggestions = [w for w in common_words if len(w) == len(word)]
        return {'result': 'Did you mean?', 'suggestions': suggestions}

