import requests
from flask import Flask, request

app = Flask(__name__)

WEATHER_API = "https://api.weatherapi.com/v1/current.json"
API_KEY = "your_api_key_here"

@app.route("/get_weather")
def get_weather():
    '''
    Get the city from the request, fetch weather data for that city, 
    and return a friendly response in South African Indian style
    '''
    city = request.args.get('city', 'Durban')
    params = {'key': API_KEY, 'q': city}

    try:
        response = requests.get(WEATHER_API, params=params)
        data = response.json()
        temp = data['current']['temp_c']
        condition = data['current']['condition']['text']

        if temp > 30:
            return f"Eish, {city} is burning at {temp}°C! {condition} weather, better stay indoors, yaar."
        elif temp > 20:
            return f"Lekker temperature in {city} - {temp}°C and {condition}. Perfect for a braai, hey!"
        else:
            return f"Brrr, {city} is chilly at {temp}°C. {condition} weather, better wear a jersey, bhai."
    except:
        return "Hawu! Couldn't fetch weather data. Maybe check the city name, ne?"

